const MUST = [
  '(AI OR "large language model" OR LLM OR 生成式)'
];
const MUST_NOT = [

];

const CFG = {
  QUERY: `${MUST.join(' AND ')} ${MUST_NOT.map(x => `-${x}`).join(' ')}`,
  LANGUAGE: 'en',
  FROM_DAYS: 1,
  MAX_ARTICLES: 50,
  TAKE_TOP: 30,
  OPENAI_CHAT: 'gpt-4o-mini',
  OPENAI_IMAGE: 'gpt-image-1',
  COVER_SIZE: '1024x576',
  BODY_SIZE: '1024x1024',
  BRAND: {
    palette: ['#0F172A','#22D3EE','#A78BFA'],
    style: 'editorial illustration, semi-flat, clean, minimal, soft lighting',
    negatives: 'text, watermark, logo, brand, people, realistic faces, hands, busy background'
  },
  // 建议改为：四大分析/洞察优先
  PREFERRED_CATEGORIES : ['tech_insight','industry_insight','deep_tech','product_insight'],

  WEIGHTS : {
    // ——基础权重（总分贡献占比）——
    base: { sourceTrust: 0.25, recency: 0.15, length: 0.15 },

    // ——正向信号（每命中一次的基点，内部会封顶/衰减）——
    signals: {
      // 洞察/分析
      insight: {
        titleCue: 12,      // 标题/URL含 how/why/analysis/解读/洞察/详解/拆解
        keyword: 10,       // 文内 analysis/deep dive/inside/趋势/产业链 等
        industry: 10,      // 芯片/供应链/封装/HBM/产能/节点nm 等行业词
        longform: 8,       // 文本较长（>1500字节）额外加
        trustedHost: 6     // 可信媒体（BBC/FT/Reuters/WSJ/Ars/Wired…）
      },
      // 技术进展
      tech: {
        terms: 6,          // architecture/ablation/SOTA/quantization/MoE 等
        paper: 9,          // arXiv/OpenReview 链接或提及
        code: 7,           // GitHub/HF 仓库
        benchmark: 7,      // MMLU/GSM8K/ImageNet/COCO/GLUE…
        numbers: 2         // 有指标/百分比/大数（轻微加）
      }
    },

    // ——负向信号（每命中一次的扣分；strong insight/tech 时会折扣）——
    penalties: {
      pr: 9,               // PR/活动/发布会/获奖/合作/招聘/调查
      policy: 7,           // 纯政策/法案/合规（分析类会折扣）
      productNews: 4       // 纯产品发布口径（无技术/无拆解）
    },
    dampIfStrong: {        // 有料则“罚款打折”
      threshold: 18,       // insightBoost+techBoost ≥ 18
      factor: 0.5
    },

    // ——类别乘数（最后乘以这个系数，决定“谁更上头条”）——
    categoryMultiplier: {
      tech_insight:     1.25,  // 技术分析/技术洞察 —— 最高
      industry_insight: 1.25,  // 行业分析/行业洞察 —— 最高
      deep_tech:        1.12,  // 论文/基准/代码等“硬技术进展”
      product_insight:  1.08,  // 产品架构拆解/对比评测
      product_news:     0.85,  // 纯上新/公告
      policy_news:      0.80,  // 纯政策新闻
      pr_event:         0.60,  // PR/活动/获奖/招聘等
      other:            0.75
    },

    // ——时效曲线（洞察类不用太追 24h 热点）——
    recencyHalfLifeHours: 96   // 半衰期 96h：4 天内仍有权重
  }
};

CFG.FROM_ISO = new Date(Date.now() - CFG.FROM_DAYS*24*60*60*1000).toISOString();
return [{json: CFG}];

/***********************
 * ScoreSelect (v2) — 深度筛选与加权排序
 * 期望输入：items[0].json.articles  (NewsAPI 风格)
 * 期望可选：$items('SetConfig',0,0).json 里含:
 *   - PREFERRED_CATEGORIES: ['tech_insight','industry_insight','deep_tech','product_insight'] 等
 *   - WEIGHTS: 见下 DEFAULT_WEIGHTS，可在 SetConfig 覆盖
 * 产出：{ primary, related, candidates }
 ***********************/

function deepMerge(t, s) {
  if (!s || typeof s !== 'object') return t;
  for (const k of Object.keys(s)) {
    const v = s[k];
    if (v && typeof v === 'object' && !Array.isArray(v)) {
      if (!t[k] || typeof t[k] !== 'object') t[k] = {};
      deepMerge(t[k], v);
    } else t[k] = v;
  }
  return t;
}

const DEFAULT_WEIGHTS = {
  base: { sourceTrust: 0.25, recency: 0.15, length: 0.15 }, // 基础分占比
  signals: {
    insight: {
      titleCue: 12,     // 标题/URL: how/why/analysis/解读/洞察/详解/拆解...
      keyword: 10,      // 文内: analysis/deep dive/inside/趋势/产业链...
      industry: 10,     // 芯片/供应链/封装/HBM/工艺/节点nm...
      longform: 8,      // >1500 字节
      trustedHost: 6    // 可信媒体
    },
    tech: {
      terms: 6,         // architecture/ablation/SOTA/quantization/MoE...
      paper: 9,         // arXiv/OpenReview
      code: 7,          // GitHub/HuggingFace
      benchmark: 7,     // MMLU/GSM8K/ImageNet/COCO/GLUE...
      numbers: 2        // 成熟指标/百分比/大数
    }
  },
  penalties: {
    pr: 9,              // PR/活动/获奖/合作/招聘
    policy: 7,          // 纯政策
    productNews: 4      // 纯产品发布口径（无拆解）
  },
  dampIfStrong: { threshold: 18, factor: 0.5 }, // 有料则罚款打折
  categoryMultiplier: {
    tech_insight:     1.25, // 技术分析/技术洞察
    industry_insight: 1.25, // 行业分析/行业洞察
    deep_tech:        1.12, // 论文/benchmark/代码
    product_insight:  1.08, // 架构拆解/对比评测
    product_news:     0.85, // 纯发布
    policy_news:      0.80, // 纯政策
    pr_event:         0.60, // PR/活动
    other:            0.75
  },
  recencyHalfLifeHours: 96
};

// —— 输入与配置 —— //
const in0 = (Array.isArray(items) && items[0] && items[0].json) ? items[0].json : {};
const rawArts = Array.isArray(in0.articles) ? in0.articles : [];
let cfg = {};
try { cfg = ($items('SetConfig', 0, 0) && $items('SetConfig',0,0).json) || {}; } catch (e) { cfg = {}; }
const preferred = Array.isArray(cfg.PREFERRED_CATEGORIES)
  ? cfg.PREFERRED_CATEGORIES
  : ['tech_insight','industry_insight','deep_tech','product_insight'];

const W = deepMerge(JSON.parse(JSON.stringify(DEFAULT_WEIGHTS)), cfg.WEIGHTS || {}); // 深合并权重
const takeTop = Number(cfg.TAKE_TOP || 30);

// —— 工具 —— //
const now = Date.now();
function host(u){ try{ return new URL(u).hostname.replace(/^www\./,''); } catch { return ''; } }
function hours(iso){ const t = new Date(iso || now).getTime(); return Math.max(1,(now - t)/36e5); }
function recencyScore(h){
  // 半衰期：W.recencyHalfLifeHours
  const half = Math.max(24, Number(W.recencyHalfLifeHours||96));
  // 映射到 0~20 区间
  const decay = Math.pow(0.5, h/half);
  return Math.round(20 * decay);
}
function lengthScore(len){
  // 0~12 阶梯
  return len>6000?12: len>3000?10: len>1500?7: len>800?5: 3;
}
function hasAny(text, arr){
  text = text || '';
  for (const term of arr) {
    const re = new RegExp(term, 'i');
    if (re.test(text)) return true;
  }
  return false;
}
function countAny(text, arr){
  text = text || '';
  let n=0;
  for (const term of arr) {
    const re = new RegExp(term, 'i');
    if (re.test(text)) n++;
  }
  return n;
}

// —— 域名可信度 —— //
const RE_RESEARCH = /(arxiv\.org|ar5iv|openreview\.net|jmlr\.org|aclanthology\.org|openaccess\.thecvf\.com|neurips\.cc|icml\.cc|iclr\.cc|ai\.googleblog\.com|deepmind\.google|openai\.com|anthropic\.com|microsoft\.com\/research|meta\.ai|huggingface\.co)/i;
const RE_TRUSTED  = /(bbc\.com|reuters\.com|bloomberg\.com|ft\.com|wsj\.com|nytimes\.com|theinformation\.com|wired\.com|arstechnica\.com|semianalysis\.com|nikkei\.com|economist\.com|cnbeta\.com|36kr\.com)/i;

// —— 信号词 —— //
const TITLE_CUES = ['\\bhow\\b','\\bwhy\\b','analysis','explained','deep\\s*dive','inside','what\\s+it\\s+means','解读','解析','详解','洞察','拆解'];
const INSIGHT_KEYWORDS = ['analysis','explainer','deep\\s*dive','insight','trend','supply\\s*chain','what\\s+it\\s+means','趋势','洞察','解读','解析','详解','拆解','产业链'];
const INDUSTRY_TERMS = [
  'semiconductor','chip','gpu','npu','accelerator','foundry','node\\s*\\d+nm','capacity','capex','packaging','hbm','cowos','chiplet','eda','lithography','euv','duv','tsmc','samsung','smic','nvidia','huawei','ascend','gaudi','供应链','产能','良率','封装','工艺','芯片','半导体','HBM','CoWoS'
];
const TECH_TERMS = [
  'architecture','ablation','sota','quantiz','lora','moe','diffusion','transformer','scaling\\s*law','tokenizer','throughput','latency','evals?','ROC','AUC','F1','BLEU','cross[-\\s]*entropy'
];
const BENCHMARKS = ['MMLU','GSM8K','HumanEval','ImageNet','COCO','SQuAD','SuperGLUE','Big-Bench','BBH','Math'];
const PR_TERMS = ['press\\s*release','roadmap','partnership','collaboration','merger','grant','funding','acquisition','award','summit','conference','webinar','keynote','event','giveaway','hiring','job','internship','survey'];
const POLICY_TERMS = ['regulation','law','act','bill','guideline','governance','ethics','EU\\s*AI\\s*Act','FTC','制裁','禁令','合规','监管'];
const PROD_NEWS = ['launch(es|ed)?','introduc(es|ed)','rolls\\s*out','announc(es|ed)','GA\\b','\\bbeta\\b','preview','SDK','toolkit','integration','Gemini','Copilot','Claude','Llama\\s*\\d'];

// —— 读取输入 —— //
const arts = rawArts.map(a => ({
  title: a.title || '',
  url: a.url || '',
  description: a.description || '',
  content: a.content || '',
  author: a.author || '',
  source: (a.source && a.source.name) || '',
  publishedAt: a.publishedAt || '',
})).filter(a => a.title && a.url);

if (!arts.length) {
  // 不抛错，给空但结构化的结果，便于下游兜底
  return [{ json: { primary: null, related: [], candidates: [] } }];
}

// —— 打分 —— //
const scored = [];
for (const a of arts) {
  const hn = host(a.url);
  const txt = `${a.title}\n${a.description}\n${a.content||''}`;
  const titleUrl = `${a.title} ${a.url}`;
  const len = (txt||'').length;

  // 基础：源站/时间/长度
  const srcScore = RE_RESEARCH.test(hn) ? 32 : RE_TRUSTED.test(hn) ? 24 : 12;
  const base = (W.base.sourceTrust * srcScore)
             + (W.base.recency * recencyScore(hours(a.publishedAt)))
             + (W.base.length * lengthScore(len));

  // 技术正信号
  const techHits = countAny(txt, TECH_TERMS);
  const hasArxiv = /arxiv\.org|ar5iv|openreview\.net/i.test(a.url) || /arXiv/i.test(txt);
  const hasCode  = /github\.com|huggingface\.co\/(papers|datasets|models)/i.test(a.url) || /GitHub|repository|code/i.test(txt);
  const benchHit = hasAny(txt, BENCHMARKS);
  const numbers  = ((txt.match(/\b\d{2}%|\b\d{3,4}\b/g)||[]).length >= 2) ? 1 : 0;

  let techBoost = 0;
  techBoost += W.signals.tech.terms * Math.min(3, techHits);
  techBoost += W.signals.tech.paper * (hasArxiv ? 1 : 0);
  techBoost += W.signals.tech.code  * (hasCode ? 1 : 0);
  techBoost += W.signals.tech.benchmark * (benchHit ? 1 : 0);
  techBoost += W.signals.tech.numbers   * numbers;

  // 洞察/分析信号
  const titleCue   = hasAny(titleUrl, TITLE_CUES) ? 1 : 0;
  const insightKW  = countAny(txt, INSIGHT_KEYWORDS);
  const industryKW = countAny(txt, INDUSTRY_TERMS);
  const longform   = len > 1500 ? 1 : 0;
  const trusted    = RE_TRUSTED.test(hn) ? 1 : 0;

  let insightBoost = 0;
  insightBoost += W.signals.insight.titleCue    * titleCue;
  insightBoost += W.signals.insight.keyword     * Math.min(3, insightKW);
  insightBoost += W.signals.insight.industry    * Math.min(3, industryKW);
  insightBoost += W.signals.insight.longform    * longform;
  insightBoost += W.signals.insight.trustedHost * trusted;

  // 负信号
  const prHits = countAny(txt, PR_TERMS);
  const policyHits = countAny(txt, POLICY_TERMS);
  const prodHits = countAny(txt, PROD_NEWS);
  const hardBlock = /bug\\s*bounty|vulnerability\\s*reward|reward\\s*program/i.test(txt);

  let penalty = (W.penalties.pr * prHits)
              + (W.penalties.policy * policyHits)
              + (W.penalties.productNews * prodHits);
  if ((techBoost + insightBoost) >= (W.dampIfStrong?.threshold || 18)) {
    penalty *= (W.dampIfStrong?.factor || 0.5);
  }

  // 分类（放宽洞察判定；标题/URL信号有效）
  let category = 'other';
  if (hardBlock) {
    category = 'blocked';
  } else if ((titleCue || insightKW) && (techHits || hasArxiv || hasCode || benchHit)) {
    category = 'tech_insight'; // 技术分析/技术洞察
  } else if (
    (industryKW >= 1) &&
    (titleCue || insightKW || trusted)
  ) {
    category = 'industry_insight'; // 行业分析/行业洞察
  } else if (hasArxiv || hasCode || benchHit || techHits >= 2) {
    category = 'deep_tech';
  } else if (prodHits >= 1 && (titleCue || insightKW)) {
    category = 'product_insight';
  } else if (policyHits >= 1 && (techBoost + insightBoost) < 12) {
    category = 'policy_news';
  } else if (prHits >= 1 && (techBoost + insightBoost) < 12) {
    category = 'pr_event';
  } else if (prodHits >= 1) {
    category = 'product_news';
  }

  // 总分 + 类别乘数
  let score = base + techBoost + insightBoost - penalty;
  const mult = (W.categoryMultiplier && W.categoryMultiplier[category]) || 1;
  score = score * mult;

  // 是否保留到候选（严格集）
  const keepStrict = !hardBlock && preferred.includes(category);

  scored.push({
    ...a,
    QualityScore: Math.round(score),
    host: hn,
    _base: Math.round(base),
    _techBoost: Math.round(techBoost),
    _insightBoost: Math.round(insightBoost),
    _penalty: Math.round(penalty),
    _mult: mult,
    signals: {
      category, srcScore, len,
      techHits, hasArxiv, hasCode, benchHit, numbers,
      titleCue, insightKW, industryKW, longform, trusted,
      prHits, policyHits, prodHits
    },
    _keepStrict: keepStrict
  });
}

// —— 去重（近似按标题） —— //
const buckets = new Map();
for (const a of scored) {
  const key = (a.title||'').toLowerCase().replace(/[^\w\u4e00-\u9fa5\s]/g,' ').replace(/\s+/g,' ').trim();
  if (!buckets.has(key)) buckets.set(key, []);
  buckets.get(key).push(a);
}
let kept = [];
for (const [, group] of buckets) {
  group.sort((x,y)=> y.QualityScore - x.QualityScore);
  // 优先挑严格集的，否则取分最高
  const strictTop = group.find(g => g._keepStrict);
  kept.push(strictTop || group[0]);
}

// —— 只取严格集；若空，则宽松兜底 —— //
let strict = kept.filter(x => x._keepStrict);
strict.sort((a,b)=> b.QualityScore - a.QualityScore);

if (!strict.length) {
  // 宽松兜底：可信媒体 + 行业/分析信号（标题/描述级别），但排除奖励计划类
  const loose = kept.filter(x => {
    if (/bug\\s*bounty|vulnerability\\s*reward|reward\\s*program/i.test(`${x.title}\n${x.description}\n${x.content||''}`)) return false;
    const looksInsight = x.signals.industryKW >= 1 || x.signals.titleCue || x.signals.insightKW >= 1;
    const trusted = RE_TRUSTED.test(x.host);
    return trusted && looksInsight;
  });
  strict = loose.length ? loose : kept; // 再不行就直接用 kept，绝不空
}

strict.sort((a,b)=> b.QualityScore - a.QualityScore);
const finalList = strict.slice(0, Math.min(takeTop, strict.length));

const primary = finalList[0] || null;
const related = finalList.slice(1, 4);
return [{ json: { primary, related, candidates: finalList, weights: W, preferred } }];


