    const match = combined.match(/\\{[\\s\\S]*\\}/);
    if (match) {
      try {
        payload = JSON.parse(match[0]);
      } catch (innerError) {
        payload = { markdown: combined, prompts: [] };
      }
    } else {
      payload = { markdown: combined, prompts: [] };
    }
  }
}
